// ---------------------------------------------------------------------------
// Go helpers for SVG graph components
// ---------------------------------------------------------------------------

// freqDBGridLine holds position info for a dB horizontal grid line.
type freqDBGridLine struct {
	Y      float64
	IsZero bool
}

// freqDBGrid returns horizontal grid lines for the frequency response graph.
func freqDBGrid(filterType string, w, h float64) []freqDBGridLine {
	var dbMin, dbMax, step float64
	if filterType == "highpass" || filterType == "lowpass" {
		dbMin, dbMax, step = -30, 3, 6
	} else {
		dbMin, dbMax, step = -15, 15, 5
	}

	var lines []freqDBGridLine
	for db := dbMin; db <= dbMax; db += step {
		y := h - (db-dbMin)/(dbMax-dbMin)*h
		lines = append(lines, freqDBGridLine{Y: y, IsZero: db == 0})
	}
	return lines
}

func gridLineColor(isZero bool) string {
	if isZero {
		return "rgba(255,255,255,0.2)"
	}
	return "rgba(255,255,255,0.06)"
}

func gridLineWidth(isZero bool) string {
	if isZero {
		return "0.75"
	}
	return "0.5"
}

// computeFreqPath dispatches to the correct frequency response computation.
func computeFreqPath(filter filters.FilterStackEntry, filterType string, w, h float64) string {
	switch filterType {
	case "equalizer":
		freq := filters.ParamFloat(filter.Params, "frequency", 3000)
		width := filters.ParamFloat(filter.Params, "width", 2000)
		gain := filters.ParamFloat(filter.Params, "gain", 4)
		return filters.ComputePeakingResponse(freq, width, gain, w, h).PathD
	case "bass":
		gain := filters.ParamFloat(filter.Params, "gain", 0)
		return filters.ComputeShelfResponse("low", 200, gain, w, h).PathD
	case "treble":
		gain := filters.ParamFloat(filter.Params, "gain", 0)
		return filters.ComputeShelfResponse("high", 4000, gain, w, h).PathD
	case "highpass":
		freq := filters.ParamFloat(filter.Params, "frequency", 200)
		return filters.ComputePassResponse("high", freq, w, h).PathD
	case "lowpass":
		freq := filters.ParamFloat(filter.Params, "frequency", 3000)
		return filters.ComputePassResponse("low", freq, w, h).PathD
	default:
		return ""
	}
}

// dynamicsGridLine holds position info for an axis grid line.
type dynamicsGridLine struct {
	X float64
	Y float64
}

// dynamicsDBGrid returns grid lines for the dynamics curve graph at -48, -36, -24, -12 dB.
func dynamicsDBGrid(w, h float64) []dynamicsGridLine {
	steps := []float64{-48, -36, -24, -12}
	var lines []dynamicsGridLine
	for _, db := range steps {
		frac := (db - (-60)) / (0 - (-60))
		lines = append(lines, dynamicsGridLine{
			X: frac * w,
			Y: h - frac*h,
		})
	}
	return lines
}

// computeDynamicsCurve extracts compressor params and computes the curve.
func computeDynamicsCurve(filter filters.FilterStackEntry) filters.DynamicsCurve {
	threshold := filters.ParamFloat(filter.Params, "threshold", -20)
	ratio := filters.ParamFloat(filter.Params, "ratio", 4)
	return filters.ComputeDynamicsCurve(threshold, ratio, 120, 80)
}

// vignetteGradientStyle returns an inline CSS style for a vignette radial gradient preview.
func vignetteGradientStyle(filter filters.FilterStackEntry) string {
	amount := filters.ParamFloat(filter.Params, "amount", 0.5)
	// Map amount (0-1) to opacity for the vignette preview
	opacity := amount
	if opacity < 0 {
		opacity = 0
	}
	if opacity > 1 {
		opacity = 1
	}
	return fmt.Sprintf(
		"background: radial-gradient(ellipse at center, transparent 40%%, rgba(0,0,0,%.2f) 100%%)",
		opacity,
	)
}

