// lutSwatchOption is a simplified option for the swatch strip.
type lutSwatchOption struct {
	Value string
	Label string
}

// lutSwatchOptions returns the LUT options for the swatch strip.
func lutSwatchOptions() []lutSwatchOption {
	return []lutSwatchOption{
		{"none", "Off"},
		{"cinematic_warm", "Warm"},
		{"cinematic_cool", "Cool"},
		{"film_noir", "Noir"},
		{"bleach_bypass", "Blch"},
		{"orange_teal", "O&T"},
		{"vintage_fade", "Vint"},
		{"high_contrast", "HiCn"},
		{"pastel", "Pstl"},
		{"golden_hour", "Gold"},
		{"moonlit", "Moon"},
	}
}

// lutCSSFilter returns a CSS filter() approximation for a LUT preset name.
func lutCSSFilter(preset string) string {
	switch preset {
	case "cinematic_warm":
		return "sepia(0.3) saturate(1.4) brightness(1.05)"
	case "cinematic_cool":
		return "saturate(0.8) hue-rotate(10deg) brightness(1.05)"
	case "film_noir":
		return "grayscale(1) contrast(1.3) brightness(0.9)"
	case "bleach_bypass":
		return "saturate(0.5) contrast(1.4) brightness(1.1)"
	case "orange_teal":
		return "sepia(0.2) hue-rotate(-10deg) saturate(1.6)"
	case "vintage_fade":
		return "sepia(0.4) contrast(0.9) brightness(1.1) saturate(0.7)"
	case "high_contrast":
		return "contrast(1.6) saturate(1.2)"
	case "pastel":
		return "saturate(0.5) brightness(1.2)"
	case "golden_hour":
		return "sepia(0.35) saturate(1.5) brightness(1.1)"
	case "moonlit":
		return "saturate(0.6) hue-rotate(30deg) brightness(0.85)"
	default:
		return "none"
	}
}

// ---------------------------------------------------------------------------
// Text position preview helpers
// ---------------------------------------------------------------------------

// textPositionDotStyle returns inline CSS to position a small dot inside
// a 16:9 box according to the named position string.
func textPositionDotStyle(pos string) string {
	var top, left string
	switch pos {
	case "top-left":
		top, left = "10%", "5%"
	case "top-center":
		top, left = "10%", "calc(50% - 3px)"
	case "top-right":
		top, left = "10%", "calc(95% - 6px)"
	case "center":
		top, left = "calc(50% - 3px)", "calc(50% - 3px)"
	case "bottom-left":
		top, left = "calc(90% - 6px)", "5%"
	case "bottom-center":
		top, left = "calc(90% - 6px)", "calc(50% - 3px)"
	default: // bottom-right
		top, left = "calc(90% - 6px)", "calc(95% - 6px)"
	}
	return fmt.Sprintf("top:%s;left:%s", top, left)
}

// textPreviewLabelStyle returns inline CSS to position the text label
// inside the preview box.
func textPreviewLabelStyle(pos string) string {
	switch pos {
	case "top-left":
		return "top:2px;left:2px"
	case "top-center":
		return "top:2px;left:50%;transform:translateX(-50%)"
	case "top-right":
		return "top:2px;right:2px"
	case "center":
		return "top:50%;left:50%;transform:translate(-50%,-50%)"
	case "bottom-left":
		return "bottom:2px;left:2px"
	case "bottom-center":
		return "bottom:2px;left:50%;transform:translateX(-50%)"
	default: // bottom-right
		return "bottom:2px;right:2px"
	}
}

